from flask import Flask, redirect, request, jsonify, session, url_for
import requests
import json
import os
from urllib.parse import urlencode

app = Flask(__name__)
app.secret_key = os.urandom(24)

CLIENT_ID = 'your_client_id'
CLIENT_SECRET = 'your_client_secret'
AUTHORIZATION_ENDPOINT = 'https://your-idp.com/oauth2/authorize'
REDIRECT_URI = 'http://localhost:5000/callback'
TOKEN_ENDPOINT = 'https://your-idp.com/oauth2/token'
USERINFO_ENDPOINT = 'https://your-idp.com/oauth2/userinfo'

@app.route('/')
def home():
    if 'id_token' in session:
        return 'Logged in as: ' + session['userinfo']['email']
    else:
        return redirect(url_for('login'))

@app.route('/login')
def login():
    params = {
        'client_id': CLIENT_ID,
        'redirect_uri': REDIRECT_URI,
        'scope': 'openid',
        'response_type': 'id_token',
    }
    auth_url = f'{AUTHORIZATION_ENDPOINT}?{urlencode(params)}'
    return redirect(auth_url)

@app.route('/callback')
def callback():
    id_token = request.args.get('id_token')
    if id_token:
        session['id_token'] = id_token
        headers = {'Authorization': f'Bearer {id_token}'}
        userinfo_response = requests.get(USERINFO_ENDPOINT, headers=headers)
        session['userinfo'] = userinfo_response.json()
        return redirect(url_for('home'))
    return 'Authentication failed', 401

if __name__ == '__main__':
    app.run(debug=True)